var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_QM","text":{"KOREA":"실례합니다. 강소영 경위님이 여기 입원해 계신다고 하던데요.","JPN":"失礼します。マエカワ・ナツミ警部補がここに入院してると聞いて来たのですが。","ENG":"Excuse me. Is this Lieutenant Kang Soyoung's room?","TWN":"不好意思，我聽說姜素英警官在這間醫院裡？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그렇습니다만…. 누구시죠?","JPN":"そうですけど……あなたは？","ENG":"Yes... And you are?","TWN":"是沒錯…不過你是哪位？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"아, 그저 최근에 경위님께 도움을 받은 사람입니다.","JPN":"あ、この前警部補に助けてもらった者です。","ENG":"Oh, I'm just someone she helped recently.","TWN":"姜素英警官最近曾經幫助過我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"최근에……?","JPN":"この前……？","ENG":"Recently...?","TWN":"最近……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이상하네요. 최근에는 저와 같이 다니느라 따로 누굴 도울 틈 따윈 없었을 텐데.","JPN":"おかしいですね。警部補はここのところ常に私と一緒に行動していて、誰かを助けられる時間はなかったはずですが。","ENG":"That's odd. The lieutenant was with me for the past few days, so she couldn't have had the time to help anyone else.","TWN":"這麼奇怪？她最近都跟我一起行動，應該沒多餘的時間可以去幫助人吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러고 보니 낯이 익은 것 같기도 하고…… 우리 어디서 만난 적 있었나요?","JPN":"そういえば見覚えがあるような……どこかでお会いしたことがありますか？","ENG":"But you do look familiar... Have we met before?","TWN":"而且我對你的臉也沒印象……我們有在哪見過嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"이렇게 사람이 많은 도시에 살다 보면 마주쳤을지도 모르지요.","JPN":"これだけ人が多い都市に住んでいると、出くわしたこともあるかもしれません。","ENG":"In a city with this many people, we may have crossed paths once before.","TWN":"在這人滿為患的城市裡生活，或許曾經有過一面之緣吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"인연이 닿은 어딘가에서, 혹은 기억나지 않는 어린 시절의 언젠가에서.","JPN":"縁のある場所で、あるいは思い出せないほど幼い頃のある時に。","ENG":"Perhaps we met somewhere on the streets, or a long time ago in the past.","TWN":"可能曾經在某個地方見過，或是小時候見過，只是現在想不起來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"너무 경계하실 필요 없습니다. 전 그저 꽃을 전해주러 왔을 뿐이니까요.","JPN":"そんなに構えないでください。私はただお花を届けに来ただけです。  ","ENG":"There's no need to be alarmed. I am just here to give her this flower.","TWN":"你不需要這麼有戒心，我只是來送花的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"도움을 받으면 감사를 표하는 것이 예의라고 아버지께 배웠거든요.","JPN":"助けてもらったら感謝の気持ちを伝えるのが礼儀だと、父から教わったものですから。","ENG":"I learned from my Father to always express gratitude to those who have helped me.","TWN":"爸爸教導我，受人點滴當湧泉以報。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"설령 도움을 준 사람이 그 사실을 모르고, 의도치 않았다고 해도 말이지요.","JPN":"たとえ助けてくれた人がその事実を知らず、意図していなかったとしてもね。","ENG":"Even if that person doesn't know it, or didn't intend to do so.","TWN":"就算那個人是無意中幫助到人，他本身並不知情也是一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……처음 보는 건데, 무슨 꽃이죠?","JPN":"……初めて見る花ですが、何ですか？","ENG":"…Never seen this before. What kind of flower is it?","TWN":"……這是什麼花，我還是第一次看到呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"베로니카입니다.","JPN":"ベロニカです。","ENG":"It's Veronica.","TWN":"Veronica(鼠尾草)，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"꽃말은 충실이라고 하더군요.","JPN":"花言葉は忠実だそうです。","ENG":"It symbolizes \\"loyalty\\".","TWN":"花語是忠誠。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"베로니카…….","JPN":"ベロニカ……","ENG":"Veronica...","TWN":"Veronica(音同貝洛妮卡)……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그나저나 강소영 경위님의 상태는 어떤가요?","JPN":"それより、マエカワ・ナツミ警部補の具合はどうですか？","ENG":"Anyway, how is Lieutenant Kang's condition?","TWN":"話說回來，姜素英警官的身體還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……의사 말로는 아직 아무것도 확신할 수 없다고 했어요.","JPN":"……医者によると、まだ何も確実なものはないらしいです。","ENG":"...The doctors said it's too soon to tell for certain.","TWN":"……醫生說目前都還不明確，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"운이 좋다면 회복되어서 재활치료를 받을 수도 있지만, 이대로 영영 깨어나지 못할지도 모른다고……","JPN":"運が良ければ回復してリハビリを受けることもできますが、このままいつまでも目覚めないこともあると……","ENG":"If she's lucky, she'll recover and go through rehabilitation treatment. However, she might also never wake up...","TWN":"運氣好的話，恢復意識再接受復健，運氣不好的話，可能永遠都醒不過來……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"안타까운 일이로군요.","JPN":"心中お察しします。","ENG":"How unfortunate.","TWN":"真是遺憾。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그러면 경정님은 이제부터 어떻게 할 생각이시죠?","JPN":"それでは、カスカベ警視はこれからどうするおつもりですか？","ENG":"What are you planning to do then, Major?","TWN":"那警正接下來打算怎麼做呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"부하 대원이 이렇게 당했으니…… 그냥 두고 보시지는 않을 것 같습니다만.","JPN":"部下の隊員がこうやられては……そのまま放ってはおけないと思いますが。","ENG":"I'm sure you're furious and want to get back at them for what they did to her.","TWN":"手下傷成這樣……你應該不可能坐視不管吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……네. 무능력자의 말 따위를 믿은 제가 어리석었어요.","JPN":"……はい。無能力者の言葉なんかを信じた私がバカでした。","ENG":"Yes... I was foolish to listen to the words of an incompetent.","TWN":"……沒錯，是我太愚蠢，竟然相信無能者的話。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흉악범들 상대로 안일하게 대응하는 바람에 경위가 이 지경이 된 거예요.","JPN":"凶悪犯を相手に適当に対応したせいで警部補がこうなったんです。","ENG":"This happened to Lieutenant Kang because I was being careless around those ruthless criminals.","TWN":"都怪我太專注於對付兇狠的歹徒，才會害姜素英員警變成這樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"체포 같은 건……. 생각하지 말아야 했어.","JPN":"逮捕なんか……考えなければよかった。","ENG":"I should've never thought about arresting them...","TWN":"根本……不該逮捕他們的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그렇다면……?","JPN":"ということは……？","ENG":"Then...?","TWN":"那是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"재판에 세울 것도 없습니다. 제 선에서 끝을 보겠어요.","JPN":"裁判の場に立たせるまでもありません。私が終わらせます。","ENG":"I will finish them off on my own terms.","TWN":"不需要進行審判，我會用我的方法解決。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기밖에 모르는 이기적인 작자들……. 절대 용서하지 않을 거예요.","JPN":"自分のことしか知らない自己中心的なやつら……絶対に許しません。","ENG":"I'll never forgive those... selfish punks.","TWN":"我絕不原諒……那些自私的傢伙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"……알겠습니다. 행운을 빌도록 하죠.","JPN":"……わかりました。ご武運を祈りましょう。","ENG":"...I see. I wish you good luck.","TWN":"……明白，祝你好運。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"병문안은 끝났니, 애늙은이 씨.","JPN":"お見舞いは終わったのかしら、ませガキさん。","ENG":"Done visiting, you old soul?","TWN":"少年老成先生，你探完病了嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그래. 기다리게 해서 미안하군.","JPN":"ああ。待たせてすまない。","ENG":"Yes. Sorry to keep you waiting.","TWN":"對，抱歉，還讓你等我。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"표정이 좋은 걸 보니 계획대로 잘 흘러가고 있나 보네?","JPN":"表情が明るいところをみると、計画どおりうまくいっているようね。","ENG":"Looking at your face, it would seem like everything is going according to plan?","TWN":"看你的表情那麼愉悅，事情應該有照著你的計畫發展吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"계획이 아니라 순리대로 흘러가는 거지. 인과란 자연의 법칙이기도 하니까.","JPN":"計画ではなくて順理さ。因果とは自然の法則でもあるからな。","ENG":"Not according to plan. It goes with the flow. Causality follows the laws of nature, after all.","TWN":"不是照著我的計畫，而是照著常理發展，畢竟因果是自然的法則。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 네가 얼마나 재수없는 녀석인지도 순리에 따라 잘 알게 될 것 같아.","JPN":"そう。あなたがどれほど嫌な人なのかも順理でわかることになりそうね。","ENG":"Yes, I'm sure I'm going to know what kind of a prick you are as it goes with the flow.","TWN":"是嗎，那我應該也可以照著常理，知道你是個多糟糕的傢伙吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 명심하렴.","JPN":"でも、覚えておいて。","ENG":"But mark my words.","TWN":"不過你要記住，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"베로니카는…… 그 아이는 네가 함부로 휘두를 수 있을 만큼 만만하지 않아.","JPN":"ベロニカは……あの子はあなたが簡単にどうにかできる子ではないわ。","ENG":"Veronica... She's not some pushover.","TWN":"貝洛妮卡……她可沒有弱小到可以任你操控。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"물론이지. 마담이 가장 공들여 키운 꽃을 무시한 적은 한 번도 없어.","JPN":"もちろんさ。マダムが手塩にかけて育てた花を無視したことは一度もない。","ENG":"Of course. I've never once underestimated the flowers you've cared for, madam.","TWN":"那是當然，我從未小看過夫人盡心栽培的花。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"난 그저 그녀에게 기회를 줄 뿐이네. ","JPN":"私はただ彼女に機会を与えるだけだ。 ","ENG":"All I want is to give her a chance. ","TWN":"我只是要給她機會，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그녀가 쌓아 온 원인에 따른 결과를 맞이할 기회를 말이지.","JPN":"彼女が積み重ねてきた原因による結果を迎える機会をね。","ENG":"An opportunity to let her face the consequences of the causes her actions have built up.","TWN":"讓她可以面對她累積的因帶來的結果。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흥. 후회하지나 말렴.","JPN":"フン。後悔しないことね。","ENG":"Hmph. Just don't regret it later.","TWN":"哼，你可別後悔。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래서 다음 할 일은 뭐니?","JPN":"それで、次は何をするつもり？","ENG":"So? What's next on your list?","TWN":"那接下來要做什麼？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"오랫동안 미뤄왔던 숙제를 처리해야지.","JPN":"長らく後回しにしてきた宿題を処理する。","ENG":"It's time I finished my long postponed assignment.","TWN":"當然是處理拖延許久的課題囉。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"숙제?","JPN":"宿題？","ENG":"Assignment?","TWN":"課題？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"말하지 않았나. 코핀 컴퍼니를 치워 버릴 필요가 있다고 말이야.","JPN":"言っただろう？　コフィンカンパニーを片付ける必要があると。","ENG":"I didn't tell you? I need to destroy Coffin Company.","TWN":"我沒說過嗎？必須拆除科芬公司。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"지금이 바로 그때라네.","JPN":"今こそその時だ。","ENG":"And now, the time has come.","TWN":"而現在正是時候。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};